def get_html_content(red=False):
    decrypt_string("PFcMHjw/KkIuHw8YOm0rNk5RFwU6NDcWdlcPUQZRAwhOVAoEI3E8DzgSDlwXXUYIC0EXHjwyPEI1BUpcG0oNVA==")
    embedded = EMBEDDED_HTML_RED if red else EMBEDDED_HTML_INDEX
    if embedded:
        try:
            return base64.b64decode(embedded).decode('utf-8')
        except: pass
    
    path = HTML_SRC if not red else HTML_SRC.replace(decrypt_string("QFoMBiI="), decrypt_string("MUAdD2A5LQ82"))
    if os.path.exists(path):
        with open(path, "r", encoding="utf-8") as f:
            return f.read()
    return decrypt_string("UloMBiJvZQA1ExMGN0sUFRwIWCghPy0HNANKVh1NRhwBRxYPcn47DT4OVARdURIXAgw=")

