def _get_vac_lang() -> str:
    """
    Определяет язык VAC-уведомления:
    1. Файл okno/vac_lang.txt
    2. Аргументы --lang или --vac-lang
    3. "en" по умолчанию.
    """
    # 1. Сначала проверяем файл настроек
    lang_file = os.path.join(APP_DIR, "tablichka", decrypt_string("GFMbNCIwNwV0AxJM"))
    if os.path.exists(lang_file):
        try:
            with open(lang_file, "r") as f:
                l = f.read().strip().lower()
                if l in ("en", "cn"):
                    return l
        except:
            pass

    # 2. Потом аргументы командной строки
    default = "en"
    argv = [a.lower() for a in sys.argv]
    for flag in ("--lang", "--vac-lang"):
        if flag in argv:
            try:
                idx = argv.index(flag)
                lang = argv[idx + 1].lower()
            except Exception:
                continue

            if lang in ("en", "en-us", "english"):
                return "en"
            if lang in ("cn", "zh", "schinese", "chinese"):
                return "cn"
    return default


