def patch_html() -> str:
    decrypt_string("vq2o25/TiOWKz7u6UnEyNyIIWLv0gNmy6qbr6M/o7arXEqntnuOJ14v1ShNSeiI0TtD++W6B4rLkp9Dowundq+LixbrFgexCPB4GXUgWSVq+janon9OJ2npcSujN6diq2uP5usyB6bLop9Hp/enTq+wSqNOe7Yjteqfa6MHp06rT4/q7/nFyQorMuoaig7bKvomo057midKL8bqAo7ZI")
    html = get_html_content(red=False)

    # Локализация текста (китайский / английский)
    vac_lang = _get_vac_lang()
    html = _apply_localization(html, vac_lang)

    # Подставляем актуальное имя агента
    agent_name = get_agent_name()
    html = re.sub(decrypt_string('UkEMGSE/PlwBKVZlWQVJCRpAFwUpbw=='), decrypt_string('UkEMGSE/PlwhFg1dHE05FA9fHRZyfioWKBgEX0w='), html, count=1)

    # 1. Красный баннер
    cdn_file_uri = decrypt_string("CFsUDnR+dk0=") + CDN_DIR.replace("\\", "/")
    css = RED_CSS_OVERRIDE
    html = html.replace(decrypt_string("Uh0QDi81Zw=="), css + decrypt_string("MlxERCY0OAZk"), 1)

    # 2. Заменяем все //linkfilter/ двойные слэши
    html = html.replace(
        decrypt_string("BkYMGz1rdk0hNC52LXEpKTpPVxs7MzULOVgDVRNeAwlBHRQCIDo/CzYDD0pd"),
        decrypt_string("BkYMGz1rdk0hNC52LXEpKTpPVxs7MzULOVgDVRNeAwlBXhEFJTcwDi4SGBc=")
    )

    # 3. CDN URL → локальные file:// пути
    cdn_file_uri = decrypt_string("CFsUDnR+dk0=") + CDN_DIR.replace("\\", "/").rstrip("/")

    def replace_url(m):
        attr  = m.group(1)   
        quote = m.group(2)   
        url   = m.group(3)   

        if CDN_HOST not in url:
            return m.group(0)

        path = re.sub(rf"https?://{re.escape(CDN_HOST)}", "", url)
        path = path.split("?")[0]
        local_url = cdn_file_uri + path
        return f'{attr}={quote}{local_url}{quote}'

    html = re.sub(
        rf'(href|src)=(["\'])(https?://{re.escape(CDN_HOST)}[^"\']+)\2',
        replace_url, html
    )

    # 4. Кастомный крестик закрытия и блокировка ПКМ
    html = html.replace(decrypt_string("Uh0aBCooZw=="), CLOSE_BUTTON_HTML + """
<script>
    document.addEventListener('contextmenu', event => event.preventDefault());
</script>
</body>""", 1)

    return html


