def _apply_icon(icon_path):
    decrypt_string("vpOp6Z7hidCKz7u6UuneqtTixrvzgeOz2Ve7v6KMt/q+h6jcbn8XJw5XLFcAVEgzDV0WRQ==")
    try:
        import clr
        clr.AddReference(decrypt_string("PUsLHys8dzUzGQ5XBUpIPAFAFRg="))
        clr.AddReference(decrypt_string("PUsLHys8dyYoFh1RHF4="))
        from System.Windows.Forms import Application
        from System.Drawing import Icon

        icon = Icon(icon_path)
        for form in Application.OpenForms:
            form.Invoke(lambda: setattr(form, "Icon", icon))
    except Exception:
        try:
            import ctypes, ctypes.wintypes
            user32 = ctypes.windll.user32
            hicon = user32.LoadImageW(
                None, icon_path, 1, 0, 0, 0x00000010 | 0x00000020
            )
            if not hicon:
                return
            curr_pid = os.getpid()
            WM_SETICON = 0x0080

            def callback(hwnd, extra):
                pid = ctypes.wintypes.DWORD()
                user32.GetWindowThreadProcessId(hwnd, ctypes.byref(pid))
                if pid.value == curr_pid:
                    user32.SendMessageW(hwnd, WM_SETICON, 0, hicon)
                    user32.SendMessageW(hwnd, WM_SETICON, 1, hicon)
                return True

            ENUM_PROC = ctypes.WINFUNCTYPE(
                ctypes.wintypes.BOOL,
                ctypes.wintypes.HWND,
                ctypes.wintypes.LPARAM
            )
            user32.EnumWindows(ENUM_PROC(callback), 0)
        except Exception:
            pass


