def _kill_steam_processes():
    decrypt_string("vpGo2p7pidCKx7qNo7tGqtzj+bv7cYndi/e6hqO/ts+/s6nqn9p5ES4SC1VcXB4fTuLAS5/QidyKyLu7o7u3+7+wqNmf0ojsi/66gKKMSA==")
